1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	type Item = { type: string };
11	type Step = { op: "quote"; items: Item[] };
12	type Scenario = { customer: unknown; steps: Step[] };
13	
14	const basePremiumForItem = (item: Item): number =>
15	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
16	
17	const quoteStep = (step: Step): { premium: number } => ({
18	  premium:
19	    step.items.reduce((sum, item) => sum + basePremiumForItem(item), 0) +
20	    PROCESSING_FEE,
21	});
22	
23	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
24	  results: scenario.steps.map(quoteStep),
25	});
