1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — empty + base premiums per item type
6	  it("empty item list → premium 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	  it("single sword → premium 105 G (100 base + 5 fee)", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result.results[0]).toEqual({ premium: 105 });
24	  });
25	  it("single amulet → premium 65 G", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [
29	        {
30	          op: "quote",
31	          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
32	        },
33	      ],
34	    });
35	    expect(result.results[0]).toEqual({ premium: 65 });
36	  });
37	  it("single staff → premium 85 G", () => {
38	    const result = runScenario({
39	      customer: { yearsWithMHPCO: 0 },
40	      steps: [
41	        {
42	          op: "quote",
43	          items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
44	        },
45	      ],
46	    });
47	    expect(result.results[0]).toEqual({ premium: 85 });
48	  });
49	  it("single potion → premium 45 G", () => {
50	    const result = runScenario({
51	      customer: { yearsWithMHPCO: 0 },
52	      steps: [
53	        {
54	          op: "quote",
55	          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
56	        },
57	      ],
58	    });
59	    expect(result.results[0]).toEqual({ premium: 45 });
60	  });
61	
62	  // Multiple items / components
63	  it.todo("two swords → premium 205 G (200 base + 5 fee)");
64	  it.todo("2 runes → premium 55 G (50 base + 5 fee)");
65	  it.todo("3 runes block → premium 65 G (60 base + 5 fee)");
66	  it.todo("4 runes no block → premium 105 G (100 base + 5 fee)");
67	  it.todo("7 runes → premium 180 G (175 base + 5 fee)");
68	  it.todo("2 runes + 1 moonstone no block → premium 80 G");
69	  it.todo("3 runes + 3 moonstones two blocks → premium 125 G");
70	
71	  // Item-specific modifiers
72	  it.todo("cursed sword newcomer → premium 165 G");
73	  it.todo("high enchantment (≥5) sword → premium 135 G (100 + 30 + 5)");
74	  it.todo("cursed + high enchantment sword → premium 185 G (100 + 50 + 30 + 5)");
75	  it.todo("policy with cursed sword + plain amulet → premium 215 G (160 + 50 + 5)");
76	
77	  // Policy-wide modifiers
78	  it.todo("loyal customer (≥2 years) sword → premium 85 G (100 − 20 + 5)");
79	  it.todo("first insurance surcharge sword first quote → premium 115 G (100 + 10 + 5)");
80	  it.todo("second quote contract gets 15% follow-up discount → premium 100 G (100 + 10 − 15 + 5)");
81	
82	  // Integration example
83	  it.todo("long-standing customer's second contract cursed sword enchantment 7 → premium 160 G");
84	
85	  // Rounding
86	  it.todo("rounds premium up in MHPCO's favor (197.5 → 198)");
87	
88	  // Claim — basic
89	  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
90	  it.todo("rune damage 200 → payout 100");
91	  it.todo("high enchantment (≥8) sword damage 1000 → payout 400 (50% then deductible)");
92	  it.todo("dragon material sword damage 800 → payout 700 (full then deductible)");
93	  it.todo("dragon material + enchantment 9 sword damage 1000 → payout 400 (50% wins)");
94	  it.todo("multiple damages each get own deductible (sword 500 + amulet 300 → 600)");
95	  it.todo("cap exhaustion: two successive claims of 1500 each on sword (1000/2000 cap) → 1400 then 600");
96	  it.todo("rounds payout down in MHPCO's favor (350.5 → 350)");
97	
98	  // Error cases
99	  it.todo("quote with unknown item type → throws error");
100	  it.todo("claim referencing item not in policy → throws error");
101	  it.todo("claim with negative damage amount → throws error");
102	  it.todo("claim with more damages of a type than policy covers → throws error");
103	});
